@@ -591,15 +591,162 @@ pub const Parser = struct {

         _ = try self.expect(.RPAREN);

+        // Check for OVER clause (window function)
+        var window: ?*ast.WindowSpec = null;
+        if (self.match(&[_]TokenType{.OVER})) {
